// IOrderQueue.cs + OrderQueue.cs
public interface IOrderQueue
{
    ValueTask QueueOrderAsync(int orderId, CancellationToken ct = default);
}

public class OrderQueue : IOrderQueue
{
    private readonly Channel<int> _channel;
    public OrderQueue(Channel<int> channel) => _channel = channel;

    public async ValueTask QueueOrderAsync(int orderId, CancellationToken ct = default)
        => await _channel.Writer.WriteAsync(orderId, ct);
}

public class BackgroundOrderProcessor : BackgroundService
{
    private readonly IServiceProvider _sp;
    private readonly ILogger<BackgroundOrderProcessor> _logger;
    private readonly Channel<int> _channel;

    public BackgroundOrderProcessor(
        IServiceProvider sp,
        ILogger<BackgroundOrderProcessor> logger,
        Channel<int> channel)
    {
        _sp = sp;
        _logger = logger;
        _channel = channel;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        await foreach (var orderId in _channel.Reader.ReadAllAsync(stoppingToken))
        {
            try
            {
                using var scope = _sp.CreateScope();
                var svc = scope.ServiceProvider.GetRequiredService<IOrderService>();
                await svc.ProcessAsync(orderId, stoppingToken);
                _logger.LogInformation("Order {OrderId} processed", orderId);
            }
            catch (OperationCanceledException) when (stoppingToken.IsCancellationRequested)
            {
                throw;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Order {OrderId} failed", orderId);
            }
        }
    }
}

public class CleanupService : BackgroundService
{
    private readonly IServiceProvider _sp;
    private readonly ILogger<CleanupService> _logger;
    private readonly TimeSpan _period = TimeSpan.FromHours(1);

    public CleanupService(IServiceProvider sp, ILogger<CleanupService> logger)
    {
        _sp = sp;
        _logger = logger;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        using var timer = new PeriodicTimer(_period);

        while (!stoppingToken.IsCancellationRequested &&
               await timer.WaitForNextTickAsync(stoppingToken))
        {
            try
            {
                await DoCleanupAsync(stoppingToken);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Cleanup failed");
            }
        }
    }

    private async Task DoCleanupAsync(CancellationToken ct)
    {
        using var scope = _sp.CreateScope();
        var context = scope.ServiceProvider.GetRequiredService<AppDbContext>();
        var cutoff = DateTime.UtcNow.AddDays(-30);
        var deleted = await context.AuditLogs
            .Where(a => a.CreatedAt < cutoff)
            .ExecuteDeleteAsync(ct);
        _logger.LogInformation("Deleted {Count} old audit logs", deleted);
    }
}

// Program.cs
builder.Services.AddSingleton(_ => Channel.CreateBounded<int>(
    new BoundedChannelOptions(1024) { FullMode = BoundedChannelFullMode.Wait }));
builder.Services.AddSingleton<IOrderQueue, OrderQueue>();
builder.Services.AddHostedService<BackgroundOrderProcessor>();
builder.Services.AddHostedService<CleanupService>();
